function loadState(){try{const stored=JSON.parse(localStorage.getItem("ofoq-state"));return{...defaults,...stored,products:stored?.products||defaults.products,posts:stored?.posts||defaults.posts}}catch{return structuredClone(defaults)}}
function saveState(){localStorage.setItem("ofoq-state",JSON.stringify(state));updatePoints()}
function updatePoints(){document.querySelector("#headerPoints").textContent=state.points.toLocaleString("ar-SA")}
const rewardCategoryLabels={daily:"جوائز يومية",weekly:"جوائز أسبوعية",grand:"جوائز كبرى"};
const achievementCategories={golden_achievements:{name:"الإنجازات الذهبية",icon:"✨",text:"العبادات اليومية"},golden_fortress:{name:"الحصن الذهبي",icon:"🛡️",text:"الأذكار والأوراد اليومية"},noori:{name:"نوري",icon:"📖",text:"ورد القرآن الكريم"},knowledge_station:{name:"محطة المعرفة",icon:"💡",text:"الثقافة والمعرفة"},golden_minute:{name:"الدقيقة الذهبية",icon:"⏱️",text:"المقاطع المفيدة"},health_first:{name:"صحتي أولاً",icon:"🌿",text:"العادات الصحية"}};
let selectedAchievementDate="";
function escapeHtml(value){return String(value??"").replace(/[&<>'"]/g,char=>({"&":"&amp;","<":"&lt;",">":"&gt;","'":"&#39;",'"':"&quot;"})[char])}
function formatRewardPoints(value){return Number(value||0).toLocaleString("ar-SA")+" نقطة"}
function rewardSections(){return Object.entries(rewardCategoryLabels).map(([category,label])=>{const rewards=(state.rewards||[]).filter(item=>item.category===category);return`<section class="reward-section reward-${category}"><div class="reward-section-head"><div><span>${category==="daily"?"☀":"weekly"===category?"📅":"🏆"}</span><h3>${label}</h3></div><small>${rewards.length} جوائز</small></div>${rewards.length?`<div class="reward-grid">${rewards.map(item=>{const canBuy=currentUser?.role==="student"&&state.points>=Number(item.amount);return`<article class="reward-card"><img src="${item.image}" alt="${escapeHtml(item.name)}"><div class="reward-card-info"><h4>${escapeHtml(item.name)}</h4><strong>${formatRewardPoints(item.amount)}</strong><button class="reward-buy-button" ${canBuy?"":"disabled"} onclick="buyReward(${item.id})">${canBuy?"شراء الجائزة":"الرصيد غير كافٍ"}</button></div></article>`}).join("")}</div>`:`<div class="empty-state">ستظهر الجوائز الجديدة هنا قريبًا</div>`}</section>`}).join("")}
function navigate(page){if(page==="owner"&&currentUser?.role!=="owner")return showToast("هذه الصفحة مخصصة لمالك المنصة");document.querySelectorAll(".page").forEach(el=>el.classList.remove("active"));document.querySelector(`#${page}Page`)?.classList.add("active");const pageTitle=titles[page]||["استكشف","مغامرة جديدة"];document.querySelector(".page-title .eyebrow").textContent=page==="home"?`مرحبًا يا ${currentUser?.name||"مستفيد"}`:pageTitle[0];document.querySelector("#pageTitle").textContent=pageTitle[1];document.querySelector("#homeBackButton")?.classList.toggle("hidden",page==="home");document.body.classList.toggle("subpage-open",page!=="home");renderPage(page);window.scrollTo({top:0,behavior:"smooth"})}

function switchAuthView(view){document.querySelectorAll(".auth-tab").forEach(tab=>tab.classList.toggle("active",tab.dataset.authView===view));document.querySelector("#loginForm").classList.toggle("hidden",view!=="login");document.querySelector("#requestForm").classList.toggle("hidden",view!=="request");document.querySelector("#authTitle").textContent=view==="login"?"تسجيل الدخول":"إنشاء حساب جديد";document.querySelector("#authSubtitle").textContent=view==="login"?"أدخل بيانات حسابك للوصول إلى المنصة":"أنشئ حسابك وادخل فورًا للمشاركة في البرنامج"}
async function api(path,options={}){const response=await fetch(`/api/${path}`,{credentials:"same-origin",headers:{"Content-Type":"application/json",...(options.headers||{})},...options});const data=await response.json().catch(()=>({}));if(!response.ok){const error=new Error(data.error||"تعذر الاتصال بالخادم");error.status=response.status;throw error}return data}
async function login(username,password){const data=await api("auth/login",{method:"POST",body:JSON.stringify({username,password})});currentUser=data.user;showApp()}
function showApp(){document.querySelector("#authScreen").classList.add("hidden");document.querySelector("#appShell").classList.remove("hidden");const isOwner=currentUser.role==="owner";document.querySelector(".owner-home-tile")?.classList.toggle("hidden",!isOwner&&!isSupervisor());document.querySelector(".points-pill")?.classList.toggle("hidden",isOwner||isSupervisor());document.querySelector("#topAccountName").textContent=currentUser.name;document.querySelector("#topAccountRole").textContent=isOwner?"مالك المنصة":isSupervisor()?"مشرف الأسبوع":`المستوى ${currentUser.level||1}`;const initial=currentUser.name.trim()[0]||"م";document.querySelector("#topAvatar").textContent=initial;document.querySelector("#pageGreeting").textContent=`مرحبًا يا ${currentUser.name}`;if(!isOwner&&!isSupervisor())state.points=Number(currentUser.points||0);updatePoints();loadWeeklySupervisor().then(()=>navigate("home"))}
async function logout(){try{await api("auth/logout",{method:"POST"})}catch{}currentUser=null;document.querySelector("#appShell").classList.add("hidden");document.querySelector("#authScreen").classList.remove("hidden");document.querySelector("#loginForm").reset();switchAuthView("login")}
async function submitRegistration(){const message=document.querySelector("#requestMessage"),password=document.querySelector("#requestPassword").value,confirmPassword=document.querySelector("#requestPasswordConfirm").value;message.classList.remove("success");if(password!==confirmPassword){message.textContent="كلمتا المرور غير متطابقتين";return}message.textContent="جارٍ إنشاء حسابك...";try{const data=await api("registration-requests",{method:"POST",body:JSON.stringify({name:document.querySelector("#requestName").value.trim(),username:document.querySelector("#requestUsername").value.trim(),contact:document.querySelector("#requestContact").value.trim(),educationStage:document.querySelector("#requestStage").value,note:document.querySelector("#requestNote").value.trim(),password,confirmPassword})});currentUser=data.user;document.querySelector("#requestForm").reset();message.textContent="";showApp();showToast("مرحبًا بك! تم إنشاء حسابك وأصبحت مشاركًا 🎉")}catch(error){message.textContent=error.message}}
function pageBanner(title,text,action=""){return`<div class="page-banner"><div><h2>${title}</h2><p>${text}</p></div>${action}</div>`}
function renderPage(page){if(page==="home")renderHome();if(page==="achievements")renderAchievements();if(page==="journey")renderJourney();if(page==="competitions")renderCompetitions();if(page==="episodes")renderEpisodes();if(page==="games")renderGames();if(page==="headhunters")renderHeadhunters();if(page==="challengeRace")renderChallengeRace();if(page==="store")renderStore();if(page==="posts")renderPosts();if(page==="supervisorKnight")renderSupervisorKnight();if(page==="owner")renderOwner()}

let weeklySupervisor=null;let supervisorEvalQuestions=[];async function loadWeeklySupervisor(){try{const data=await api("supervisor/assign");weeklySupervisor=data.supervisor;state.weeklySupervisorId=data.supervisor?.id||null}catch{weeklySupervisor=null;state.weeklySupervisorId=null}}
async function renderHome(){const card=document.querySelector("#managerInstructionsCard");if(!card)return;try{const data=await api("manager-instructions");document.querySelector("#managerInstructionsTitle").textContent=data.title;document.querySelector("#managerInstructionsBody").textContent=data.body;card.classList.remove("is-loading")}catch(error){card.classList.remove("is-loading");showToast(error.message)}try{if(!weeklySupervisor)await loadWeeklySupervisor()}catch{}renderHomeSupervisorSection();renderHomeEvaluationSection()}
function renderHomeSupervisorSection(){let section=document.querySelector("#homeSupervisorSection");if(!section){section=document.createElement("section");section.id="homeSupervisorSection";section.className="supervisor-weekly-card";const ref=document.querySelector("#managerInstructionsCard");ref?.parentNode?.insertBefore(section,ref.nextSibling)}if(weeklySupervisor){section.innerHTML=`<div class="supervisor-badge"><span>👑</span><div><strong>مشرف الأسبوع</strong><small>${escapeHtml(weeklySupervisor.name)}</small></div></div>`;section.classList.remove("hidden")}else section.classList.add("hidden")}
function renderHomeEvaluationSection(){const section=document.querySelector("#homeEvalSection");if(!section)return;if(currentUser?.role!=="student"){section.classList.add("hidden");return}section.classList.remove("hidden");section.innerHTML=`<div class="eval-card"><span>📋</span><div><strong>تقييم المشرفين</strong><small>شارك بتقييمك للمشرف</small></div><button class="primary-button" onclick="openSupervisorEvaluation()">تقيم</button></div>`}

function challengeRankName(rank){return rank===1?"المركز الأول":rank===2?"المركز الثاني":rank===3?"المركز الثالث":`المركز ${rank.toLocaleString("ar-SA")}`}
async function renderChallengeRace(){const page=document.querySelector("#challengeRacePage");page.innerHTML=`<div class="loading-state">جارٍ تحديث ترتيب المتسابقين...</div>`;try{const data=await api("challenge-race");if(data.teaser){page.innerHTML=`<section class="race-page-head"><button class="race-home-button" data-page="home">⌂ العودة للرئيسية</button><div><span>🏁</span><h2>سباق التحدي</h2><p>من سيعبر خط النهاية أولًا؟</p></div></section><section class="race-teaser"><span>🏆</span><h2>ترقبوا إعلان الفائز</h2></section>`;return}const rows=(data.participants||[]).map(item=>`<article class="race-row rank-${Math.min(item.rank,4)} ${Number(item.id)===Number(currentUser?.id)?"is-me":""}"><span class="race-rank">${item.rank<=3?["🥇","🥈","🥉"][item.rank-1]:item.rank.toLocaleString("ar-SA")}</span><div class="race-person"><span>${escapeHtml(item.name.trim()[0]||"م")}</span><div><strong>${escapeHtml(item.name)}</strong>${Number(item.id)===Number(currentUser?.id)?`<small>هذا أنت ✨</small>`:""}</div></div><strong class="race-points">${Number(item.points||0).toLocaleString("ar-SA")} <small>نقطة</small></strong><b class="race-position">${challengeRankName(item.rank)}</b></article>`).join("");page.innerHTML=`<section class="race-page-head"><button class="race-home-button" data-page="home">⌂ العودة للرئيسية</button><div><span>🏁</span><h2>سباق التحدي</h2><p>الترتيب يتحدث تلقائيًا حسب نقاط المشاركين</p></div></section>${rows?`<section class="race-board"><div class="race-board-head"><span>المركز</span><span>المشارك</span><span>النقاط</span><span>الترتيب</span></div>${rows}</section>`:`<div class="empty-state">لا يوجد مشاركون في السباق حاليًا</div>`}`}catch(error){page.innerHTML=`<div class="empty-state">${escapeHtml(error.message)}</div>`}}

function achievementDateLabel(date,today){if(date===today)return"اليوم";return new Date(`${date}T12:00:00`).toLocaleDateString("ar-SA",{weekday:"long",year:"numeric",month:"long",day:"numeric"})}
function moveAchievementDate(days){const value=new Date(`${selectedAchievementDate}T12:00:00`);value.setDate(value.getDate()+days);selectedAchievementDate=value.toISOString().slice(0,10);renderAchievements()}
async function renderAchievements(){const page=document.querySelector("#achievementsPage");page.innerHTML=`<div class="loading-state">جارٍ تحميل إنجازاتك...</div>`;try{const query=selectedAchievementDate?`?date=${selectedAchievementDate}`:"";const data=await api(`achievements${query}`);selectedAchievementDate=data.date;const grouped=Object.keys(achievementCategories).map(category=>{const info=achievementCategories[category],tasks=data.tasks.filter(task=>task.category===category);return`<section class="achievement-category"><div class="achievement-category-head"><span>${info.icon}</span><div><h3>${info.name}</h3><p>${info.text}</p></div><b>${tasks.filter(task=>task.completed).length}/${tasks.length}</b></div>${tasks.length?`<div class="achievement-list">${tasks.map(task=>`<button class="achievement-task ${task.completed?"completed":""}" ${task.completed||currentUser?.role!=="student"?"disabled":""} onclick="completeAchievementTask(${task.id})"><span class="achievement-check">${task.completed?"✓":""}</span><span><strong>${escapeHtml(task.title)}</strong>${task.description?`<small>${escapeHtml(task.description)}</small>`:""}</span><b>+${Number(task.points).toLocaleString("ar-SA")} ★</b></button>`).join("")}</div>`:`<div class="achievement-empty">لم يضف المالك مهامًا في هذا القسم بعد</div>`}</section>`}).join("");const earned=data.summary.badges.filter(badge=>badge.earned).length;page.innerHTML=`${pageBanner("إنجازات تتجدد كل يوم","ضع علامة عند إتمام المهمة، ويمكنك الرجوع للأيام السابقة واستدراك ما فاتك.")}<div class="achievement-date-bar"><button class="date-arrow" onclick="moveAchievementDate(-1)">اليوم السابق</button><div><small>إنجازات</small><strong>${achievementDateLabel(data.date,data.today)}</strong><input type="date" value="${data.date}" max="${data.today}" onchange="selectedAchievementDate=this.value;renderAchievements()"></div><button class="date-arrow" onclick="moveAchievementDate(1)" ${data.date>=data.today?"disabled":""}>اليوم التالي</button></div><div class="achievement-summary"><div><span>⭐</span><strong>${data.summary.points.toLocaleString("ar-SA")}</strong><small>نقاط الإنجازات</small></div><div><span>✅</span><strong>${data.summary.completedCount.toLocaleString("ar-SA")}</strong><small>مهمة مكتملة</small></div><div><span>🏅</span><strong>${earned}/${data.summary.badges.length}</strong><small>أوسمة مكتسبة</small></div></div><div class="achievement-grid">${grouped}</div><section class="achievement-badges"><div class="section-heading"><div><span class="eyebrow">تتقدم مع كل إنجاز</span><h2>أوسمتي</h2></div></div><div class="badges-row">${data.summary.badges.map(badge=>`<article class="achievement-badge ${badge.earned?"earned":"locked"}"><span>${badge.icon}</span><strong>${badge.name}</strong><small>${badge.earned?"تم الحصول عليه":`${badge.threshold} نقطة`}</small></article>`).join("")}</div></section>`}catch(error){page.innerHTML=`<div class="empty-state">${escapeHtml(error.message)}</div>`}}
async function completeAchievementTask(id){try{const result=await api(`achievements/${id}/complete`,{method:"POST",body:JSON.stringify({date:selectedAchievementDate})});state.points=result.points;currentUser.points=result.points;updatePoints();await renderAchievements();showToast(`أحسنت! أضفنا ${result.awarded} نقطة إلى رصيدك`)}catch(error){showToast(error.message)}}

function renderJourney(){document.querySelector("#journeyPage").innerHTML=`
${pageBanner("رحلتك تنمو مع كل إنجاز","أكمل الأنشطة لتفتح مناطق جديدة وتجمع الشارات والنقاط.")}
<div class="stat-grid"><div class="stat-card"><strong>68%</strong><span>نسبة إكمال الرحلة</span></div><div class="stat-card"><strong>${state.points.toLocaleString("ar-SA")}</strong><span>إجمالي نقاطك</span></div><div class="stat-card"><strong>18</strong><span>مهمة مكتملة</span></div><div class="stat-card"><strong>6</strong><span>شارات مكتسبة</span></div></div>
<section class="journey-preview journey-full"><img src="assets/family/graduation-3d.webp" alt="رحلة عائلية نحو الإنجاز"><div class="map-overlay"></div>
<button class="stage-marker stage-1 completed" onclick="showStage(1)"><span>✓</span><b>بداية الرحلة</b></button><button class="stage-marker stage-2 completed" onclick="showStage(2)"><span>✓</span><b>حديقة المعرفة</b></button><button class="stage-marker stage-3 current" onclick="showStage(3)"><span>3</span><b>مرصد العلوم</b></button><button class="stage-marker stage-4 locked" onclick="showStage(4)"><span>🔒</span><b>جزيرة الإبداع</b></button></section>`}

async function renderCompetitions(){try{const data=await api("competition-settings");data.settings.forEach(setting=>{const item=competitions.find(comp=>comp.id===Number(setting.competition_id));if(item)item.reward=Number(setting.points)})}catch(error){showToast(error.message)}document.querySelector("#competitionsPage").innerHTML=`
${pageBanner("تحديات تصنع الفرق","شارك، اجمع النقاط، وشاهد اسمك في قائمة المتصدرين.")}
<div class="filter-row"><button class="filter-button active">الكل</button><button class="filter-button">فردية</button><button class="filter-button">جماعية</button><button class="filter-button">مكتملة</button></div>
<div class="content-grid">${competitions.map(item=>`<article class="content-card"><div class="card-visual ${item.color}"><span class="tag">${item.tag}</span>${item.icon}</div><div class="card-body"><h3>${item.title}</h3><p>${item.desc}</p><div class="card-meta"><span>المكافأة: <b>${item.reward} ★</b></span><button class="card-action" onclick="openCompetition(${item.id})">${state.completedCompetitions.includes(item.id)?"مكتملة ✓":"ابدأ الآن ←"}</button></div></div></article>`).join("")}</div>`}

function renderEpisodes(){document.querySelector("#episodesPage").innerHTML=`
${pageBanner("برامج وحلقات مختارة لك","شاهد حلقات قصيرة، ثم أجب عن سؤال لتحصل على النقاط.")}
<div class="filter-row"><button class="filter-button active">أحدث الحلقات</button><button class="filter-button">العلوم</button><button class="filter-button">اللغة</button><button class="filter-button">التاريخ</button></div>
<div class="content-grid">${episodes.map((e,i)=>`<article class="content-card"><div class="card-visual ${e[4]}">${e[3]}<span class="tag">الحلقة ${i+1}</span></div><div class="card-body"><small>${e[0]}</small><h3>${e[1]}</h3><div class="card-meta"><span>▶ ${e[2]}</span><button class="card-action" onclick="playEpisode(${i})">شاهد الآن ←</button></div></div></article>`).join("")}</div>`}

function renderGames(){document.querySelector("#gamesPage").innerHTML=`
${pageBanner("العب، فكّر، وتقدّم","ألعاب قصيرة مصممة لتنمية المهارات ومنحك نقاطًا إضافية.")}
<div class="content-grid">${games.map((g,i)=>`<article class="content-card"><div class="card-visual ${g[3]}">${g[2]}</div><div class="card-body"><h3>${g[0]}</h3><p>${g[1]}</p><div class="card-meta"><span>أفضل نتيجة: ${g[4]*8}</span><button class="card-action" onclick="playGame(${i})">العب الآن ←</button></div></div></article>`).join("")}</div>`}

async function renderStore(){try{const rewardsData=await api("rewards");state.rewards=rewardsData.rewards}catch(error){return showToast(error.message)}document.querySelector("#storePage").innerHTML=`
${pageBanner("متجر الجوائز","استبدل نقاطك بجوائز يومية وأسبوعية وكبرى.")}
<section class="reward-balance"><div><small>رصيدك الحالي</small><strong><span>★</span> ${state.points.toLocaleString("ar-SA")} نقطة</strong></div><button class="primary-button" onclick="navigate('competitions')">اجمع نقاطًا أكثر</button></section>
<div class="reward-store">${rewardSections()}</div>`}

async function renderPosts(){const page=document.querySelector("#postsPage");page.innerHTML=`${pageBanner("حي الله من جانا","مجلسنا الدافي للسوالف والضحك والردود الحلوة ☕")}<div class="loading-state">نفرش المجلس ونجهز الدلال...</div>`;try{const data=await api("majlis");state.majlis=data;page.innerHTML=`
<section class="majlis-hero"><img src="assets/family/babies-3d.webp" alt="أطفال من العائلة بأسلوب ثلاثي الأبعاد مرح"><div class="majlis-hero-shade"></div><div class="majlis-hero-copy"><span>المجلس مفتوح للجميع</span><h2>حي الله من جانا</h2><p>علومٍ تسرك، وضحكة تجمعنا، وسوالف ما تنمل.</p></div><div class="majlis-live"><i></i>${data.posts.length} سالفة</div></section>
<div class="post-composer majlis-composer"><div class="composer-title"><div class="avatar">${escapeHtml(currentUser.name[0])}</div><div><strong>وش علومك يا ${escapeHtml(currentUser.name)}؟</strong><small>سالفتك وصورتك تظهر لكل أهل المجلس</small></div></div><textarea id="postText" maxlength="1200" placeholder="اكتب سالفتك هنا... ☕"></textarea><div id="postImagePreview" class="majlis-image-preview hidden"></div>${majlisPicker("postText",true)}<div class="composer-footer"><small id="postCounter">حتى 1200 حرف</small><div><label class="majlis-upload">📷 إضافة صورة<input id="postImage" type="file" accept="image/png,image/jpeg,image/webp" hidden onchange="previewMajlisImage(event,'postImagePreview')"></label><button class="primary-button" onclick="publishPost()">☕ أرسل السالفة</button></div></div></div>
<div class="majlis-feed">${data.posts.length?data.posts.map(renderMajlisPost).join(""):`<div class="majlis-empty"><span>☕</span><h3>المقلط هادي اليوم</h3><p>كن أول من يفتح باب السوالف!</p></div>`}</div>`;document.querySelector("#postText")?.addEventListener("input",event=>document.querySelector("#postCounter").textContent=`${event.target.value.length} / 1200`)}catch(error){page.innerHTML+=`<div class="empty-state">${escapeHtml(error.message)}</div>`}}

function majlisPicker(inputId,stickers=false){return`<div class="majlis-picker"><details><summary>😊 رموز تعبيرية</summary><div class="emoji-tray">${Object.entries(majlisEmojiGroups).map(([name,items])=>`<section><strong>${name}</strong><div>${items.map(item=>`<button type="button" onclick="insertMajlisEmoji('${inputId}','${item}')">${item}</button>`).join("")}</div></section>`).join("")}</div></details>${stickers?`<details><summary>🎭 ملصقات</summary><div class="sticker-tray">${majlisStickers.map((item,index)=>`<button type="button" class="sticker sticker-${index%4}" onclick="publishSticker('${item}')">${item}</button>`).join("")}</div></details>`:""}</div>`}
function formatMajlisTime(value){return new Date(`${value.replace(" ","T")}Z`).toLocaleString("ar-SA",{dateStyle:"medium",timeStyle:"short"})}
function majlisRole(item){return item.role==="owner"?"صاحب المقلط":`من أهل المقلط · المستوى ${item.level||1}`}
function reactionButtons(type,id){const value=state.majlis?.reactions?.[`${type}:${id}`]||{like:0,dislike:0,laugh:0,mine:null};return`<div class="reaction-row"><button class="${value.mine==="like"?"active":""}" onclick="reactMajlis('${type}',${id},'like')">👍 <span>${value.like||0}</span></button><button class="${value.mine==="dislike"?"active":""}" onclick="reactMajlis('${type}',${id},'dislike')">😕 <span>${value.dislike||0}</span></button><button class="${value.mine==="laugh"?"active laugh":""}" onclick="reactMajlis('${type}',${id},'laugh')">😂 <span>${value.laugh||0}</span></button></div>`}
function majlisContent(item){return`${item.content_type==="sticker"?`<div class="published-sticker">${escapeHtml(item.content)}</div>`:item.content?`<p>${escapeHtml(item.content).replace(/\n/g,"<br>")}</p>`:""}${item.image_data?`<img class="majlis-shared-image" src="${item.image_data}" alt="صورة مرفقة من ${escapeHtml(item.author)}">`:""}`}
function deleteMajlisButton(type,item){return item.can_delete?`<button class="majlis-delete" onclick="confirmDeleteMajlis('${type}',${item.id})" title="حذف">🗑 حذف</button>`:""}
function replyComposer(postId,parentId,inputId,previewId){return`<textarea id="${inputId}" maxlength="1200" placeholder="اكتب ردك هنا..."></textarea><div id="${previewId}" class="majlis-image-preview hidden"></div><div class="reply-tools">${majlisPicker(inputId)}<div><label class="majlis-upload compact">📷 صورة<input id="image-${inputId}" type="file" accept="image/png,image/jpeg,image/webp" hidden onchange="previewMajlisImage(event,'${previewId}')"></label><button onclick="publishComment(${postId},${parentId||"null"},'${inputId}')">إرسال الرد</button></div></div>`}
function renderMajlisPost(post){const comments=state.majlis.comments.filter(item=>Number(item.post_id)===Number(post.id));return`<article class="post-card majlis-post"><div class="post-head"><div class="avatar">${escapeHtml(post.author[0])}</div><div><strong>${escapeHtml(post.author)}</strong><time>${majlisRole(post)} · ${formatMajlisTime(post.created_at)}</time></div>${deleteMajlisButton("post",post)}<span class="coffee-mark">☕</span></div>${majlisContent(post)}<div class="post-actions">${reactionButtons("post",post.id)}<button class="reply-main" onclick="toggleReplyBox('post-${post.id}')">💬 <strong>رد</strong> <span>(${comments.length})</span></button></div><div class="reply-box hidden" id="reply-post-${post.id}">${replyComposer(post.id,null,`replyText-post-${post.id}`,`replyPreview-post-${post.id}`)}</div>${comments.length?`<section class="comment-tree">${comments.filter(item=>!item.parent_id).map(comment=>renderMajlisComment(comment,comments,0)).join("")}</section>`:""}</article>`}
function renderMajlisComment(comment,all,depth){const children=all.filter(item=>Number(item.parent_id)===Number(comment.id));return`<article class="majlis-comment" style="--depth:${Math.min(depth,3)}"><div class="comment-line"><div class="avatar avatar-small">${escapeHtml(comment.author[0])}</div><div class="comment-bubble"><div><strong>${escapeHtml(comment.author)}</strong><time>${majlisRole(comment)} · ${formatMajlisTime(comment.created_at)}</time>${deleteMajlisButton("comment",comment)}</div>${majlisContent(comment)}<div class="comment-actions">${reactionButtons("comment",comment.id)}<button class="clear-reply" onclick="toggleReplyBox('comment-${comment.id}')">↩ <strong>رد</strong></button></div></div></div><div class="reply-box hidden compact" id="reply-comment-${comment.id}">${replyComposer(comment.post_id,comment.id,`replyText-comment-${comment.id}`,`replyPreview-comment-${comment.id}`)}</div>${children.map(child=>renderMajlisComment(child,all,depth+1)).join("")}</article>`}

async function renderOwner(section="overview"){if(currentUser?.role!=="owner"&&!isSupervisor())return navigate("home");try{const [usersData,requestsData,rewardsData,ordersData,achievementData,challengeData,competitionData,instructionsData,gameData]=await Promise.all([api("owner/users"),api("owner/registration-requests"),api("rewards"),api("owner/reward-orders"),api("owner/achievement-tasks"),api("owner/daily-challenge-settings"),api("owner/competition-settings"),api("owner/manager-instructions"),api("owner/game-settings")]);authData.users=usersData.users;authData.requests=requestsData.requests;state.rewards=rewardsData.rewards;state.rewardOrders=ordersData.orders;state.achievementTasks=achievementData.tasks;state.challengeSettings=challengeData.settings;state.competitionSettings=competitionData.settings;state.managerInstructions=instructionsData;state.gameSettings=gameData.settings}catch(error){showToast(error.message);return}const pendingOrders=state.rewardOrders.filter(order=>order.status==="pending").length;const tabs=[["overview","نظرة عامة"],["instructions","📣 تعليمات المدير"],["challenges","نقاط المسابقات والتحديات"],["achievements","مهام الإنجازات"],["rewards","متجر الجوائز"],["rewardOrders",`طلبات الجوائز (${pendingOrders})`],["requests",`طلبات التسجيل (${authData.requests.length})`],["students","المستفيدون"],["content","المحتوى والبرامج"]];if(currentUser?.role==="owner")tabs.push(["supervisorAssign","\ud83d\udc51 تعيين مشرف الأسبوع"],["supervisorEval","\ud83d\udccb تقييم المشرفين"]);const action=section==="achievements"?`<button class="primary-button" onclick="openAchievementTaskForm()">+ مهمة يومية</button>`:section==="rewards"?`<button class="primary-button" onclick="openRewardForm()">+ جائزة جديدة</button>`:section==="students"?`<button class="primary-button" onclick="openAddUser()">+ إضافة مستفيد</button>`:"";document.querySelector("#ownerPage").innerHTML=`
${pageBanner("مرحبًا بك في مركز التحكم","أدر الحسابات وطلبات التسجيل والمحتوى والمتجر من مكان واحد.",action)}
<button class="owner-race-entry ${section==="challengeRace"?"active":""}" onclick="renderOwner('challengeRace')"><span>🏁</span><div><strong>سباق التحدي</strong><small>التحكم بعرض النتائج للمستفيدين</small></div><b>←</b></button>
<div class="owner-layout"><div>${ownerSection(section)}</div><nav class="owner-nav">${tabs.map(t=>`<button class="owner-tab ${section===t[0]?"active":""}" onclick="renderOwner('${t[0]}')">${t[1]}</button>`).join("")}</nav></div>`}
function ownerSection(section){
if(section==="challengeRace"){queueMicrotask(loadOwnerChallengeRace);return`<div class="owner-panel race-owner-panel"><div class="panel-title"><div><h3>🏁 سباق التحدي</h3><p>اختر ما سيظهر للمستفيدين في صفحة السباق.</p></div><span class="race-owner-icon">🏆</span></div><div id="ownerRaceControl" class="race-control-loading">جارٍ تحميل حالة السباق...</div></div>`}
if(section==="achievements")return ownerAchievementsSection();
if(section==="instructions"){const item=state.managerInstructions||{};return`<div class="owner-panel manager-editor"><div class="panel-title"><div><h3>📣 تعليمات المدير</h3><p>ستظهر هذه الرسالة بوضوح لجميع المستفيدين في الصفحة الرئيسية.</p></div><span class="editor-mascot">🧑‍🏫</span></div><div class="form-grid"><label class="form-field full"><span>عنوان الرسالة</span><input id="managerInstructionsTitleInput" maxlength="90" value="${escapeHtml(item.title||"")}" placeholder="مثال: رسالة المدير لك اليوم"></label><label class="form-field full"><span>التعليمات</span><textarea id="managerInstructionsBodyInput" maxlength="700" rows="8" placeholder="اكتب تعليمات ورسالة المدير...">${escapeHtml(item.body||"")}</textarea></label></div><div class="manager-editor-actions"><span>✨ سيظهر التحديث فورًا في الرئيسية</span><button class="primary-button" onclick="saveManagerInstructions()">حفظ ونشر التعليمات</button></div></div>`}
if(section==="challenges"){const win=(state.gameSettings||[]).find(item=>item.setting_key==="win_points")?.setting_value||100,million=(state.gameSettings||[]).find(item=>item.setting_key==="million_cap")?.setting_value||10000;return`<div class="owner-panel challenge-points-panel"><div class="panel-title"><div><h3>نقاط المسابقات والتحديات</h3><p>حدد المكافآت والحدود العليا لكل نوع من التحديات.</p></div><span class="owner-challenge-symbol">✦</span></div><h4 class="points-section-title">🧠 رصيد مصامخ الرؤوس</h4><div class="challenge-points-grid"><label class="challenge-point-row"><span>🏆</span><div><strong>مكافأة الفوز</strong><small>لكل فائز أو عضو في الفريق الفائز</small></div><input id="gameSetting-win_points" type="number" min="1" max="10000" value="${win}"><button onclick="saveGameSetting('win_points')">حفظ</button></label><label class="challenge-point-row"><span>💎</span><div><strong>سقف المليون نقطة</strong><small>الجائزة الواقعية القصوى للتحدي النادر</small></div><input id="gameSetting-million_cap" type="number" min="1" max="1000000" value="${million}"><button onclick="saveGameSetting('million_cap')">حفظ</button></label></div><h4 class="points-section-title">🏆 نقاط المسابقات</h4><div class="challenge-points-grid competition-points-grid">${competitions.map(item=>{const setting=(state.competitionSettings||[]).find(row=>Number(row.competition_id)===item.id);return`<label class="challenge-point-row"><span>${item.icon}</span><div><strong>${item.title}</strong><small>مكافأة إكمال المسابقة</small></div><input id="competitionPoints-${item.id}" type="number" min="1" max="10000" value="${Number(setting?.points||item.reward)}"><button onclick="saveCompetitionPoints(${item.id})">حفظ</button></label>`}).join("")}</div><h4 class="points-section-title">✦ نقاط التحديات اليومية</h4><div class="challenge-points-grid">${dailyChallengeCatalog.map(([key,name,icon])=>{const setting=(state.challengeSettings||[]).find(item=>item.challenge_key===key);return`<label class="challenge-point-row"><span>${icon}</span><div><strong>${name}</strong><small>الحد الأعلى للنقاط</small></div><input id="challengePoints-${key}" type="number" min="1" max="10000" value="${Number(setting?.max_points||100)}"><button onclick="saveChallengePoints('${key}')">حفظ</button></label>`}).join("")}</div></div>`}
if(section==="achievements")return`<div class="owner-panel"><div class="panel-title"><div><h3>مهام الإنجازات اليومية</h3><p>حدد المهمة ودرجتها وفترة ظهورها، وستتجدد يوميًا داخل الفترة المختارة.</p></div></div>${(state.achievementTasks||[]).length?`<div class="table-scroll"><table class="data-table"><thead><tr><th>المهمة</th><th>القسم</th><th>النقاط</th><th>فترة الظهور</th><th>الحالة</th></tr></thead><tbody>${state.achievementTasks.map(task=>`<tr><td><strong>${escapeHtml(task.title)}</strong>${task.description?`<small class="table-subtext">${escapeHtml(task.description)}</small>`:""}</td><td>${achievementCategories[task.category]?.icon||""} ${achievementCategories[task.category]?.name||task.category}</td><td>${Number(task.points).toLocaleString("ar-SA")}</td><td><span class="task-period">من ${new Date(`${task.start_date}T12:00:00`).toLocaleDateString("ar-SA")}<br>إلى ${task.end_date?new Date(`${task.end_date}T12:00:00`).toLocaleDateString("ar-SA"):"مفتوحة"}</span></td><td><button class="${task.active?"deliver-button":"edit-button"}" onclick="toggleAchievementTask(${task.id},${task.active?"false":"true"})">${task.active?"نشطة · إيقاف":"متوقفة · تفعيل"}</button></td></tr>`).join("")}</tbody></table></div>`:`<div class="empty-state">لا توجد مهام بعد. أضف أول مهمة يومية.</div>`}</div>`;
if(section==="rewards")return`<div class="owner-panel"><div class="panel-title"><div><h3>متجر الجوائز</h3><p>إدارة الجوائز اليومية والأسبوعية والكبرى</p></div></div>${(state.rewards||[]).length?`<div class="table-scroll"><table class="data-table rewards-table"><thead><tr><th>الصورة</th><th>اسم الجائزة</th><th>التكلفة</th><th>التصنيف</th><th>الإجراءات</th></tr></thead><tbody>${state.rewards.map(reward=>`<tr><td><img class="reward-thumb" src="${reward.image}" alt=""></td><td><strong>${escapeHtml(reward.name)}</strong></td><td>${formatRewardPoints(reward.amount)}</td><td><span class="category-badge category-${reward.category}">${rewardCategoryLabels[reward.category]}</span></td><td><div class="table-actions"><button class="edit-button" onclick="openRewardForm(${reward.id})">تعديل</button><button class="delete-button" onclick="removeReward(${reward.id})">حذف</button></div></td></tr>`).join("")}</tbody></table></div>`:`<div class="empty-state">لا توجد جوائز بعد. أضف أول جائزة من الزر أعلاه.</div>`}</div>`;
if(section==="rewardOrders")return`<div class="owner-panel"><div class="panel-title"><div><h3>طلبات الجوائز</h3><p>طلبات المستفيدين مرتبة من الأحدث</p></div></div>${(state.rewardOrders||[]).length?`<div class="table-scroll"><table class="data-table rewards-table"><thead><tr><th>الجائزة</th><th>المستفيد</th><th>النقاط</th><th>التاريخ</th><th>الحالة</th></tr></thead><tbody>${state.rewardOrders.map(order=>`<tr><td><div class="order-reward"><img class="reward-thumb" src="${order.reward_image}" alt=""><strong>${escapeHtml(order.reward_name)}</strong></div></td><td>${escapeHtml(order.user_name)}<small class="table-subtext">@${escapeHtml(order.username)}</small></td><td>${formatRewardPoints(order.points_paid)}</td><td>${new Date(order.created_at).toLocaleDateString("ar-SA")}</td><td>${order.status==="pending"?`<button class="deliver-button" onclick="markOrderDelivered(${order.id})">تأكيد التسليم</button>`:`<span class="delivered-badge">تم التسليم</span>`}</td></tr>`).join("")}</tbody></table></div>`:`<div class="empty-state">لا توجد طلبات جوائز حتى الآن</div>`}</div>`;
if(section==="requests"){const requests=authData.requests.filter(r=>r.status==="pending");return`<div class="owner-panel"><h3>طلبات التسجيل الجديدة</h3>${requests.length?requests.map(r=>`<article class="request-card"><div><strong>${escapeHtml(r.name)}</strong><p>اسم المستخدم: ${escapeHtml(r.username)} · التواصل: ${escapeHtml(r.contact)}</p><p><b>المرحلة:</b> ${escapeHtml(r.education_stage||"غير محددة")}</p>${r.note?`<p>${escapeHtml(r.note)}</p>`:""}</div><div class="request-actions"><button class="small-button" onclick="approveRequest(${r.id})">قبول</button><button class="small-button reject" onclick="rejectRequest(${r.id})">رفض</button></div></article>`).join(""):`<div class="empty-state">لا توجد طلبات تسجيل جديدة</div>`}</div>`}
if(section==="products")return`<div class="owner-panel"><h3>منتجات المتجر</h3><table class="data-table"><thead><tr><th>المنتج</th><th>السعر</th><th>المخزون</th><th></th></tr></thead><tbody>${state.products.map(p=>`<tr><td>${p.icon} ${p.name}</td><td>${p.price} نقطة</td><td>${p.stock}</td><td><button class="card-action" onclick="deleteProduct(${p.id})">حذف</button></td></tr>`).join("")}</tbody></table></div>`;
if(section==="content")return`<div class="owner-panel"><h3>المحتوى المنشور</h3><table class="data-table"><thead><tr><th>القسم</th><th>عدد العناصر</th><th>الحالة</th></tr></thead><tbody><tr><td>المسابقات</td><td>6</td><td>نشط</td></tr><tr><td>الحلقات والبرامج</td><td>24</td><td>نشط</td></tr><tr><td>التحديات اليومية</td><td>10</td><td>نشط</td></tr></tbody></table></div>`;
if(section==="supervisorAssign"){queueMicrotask(loadWeeklySupervisor);return ownerSupervisorSection()}
if(section==="supervisorEval"){queueMicrotask(loadEvalQuestionsList);return ownerEvalQuestionsSection()}
if(section==="students"){const users=authData.users.filter(u=>u.role==="student");return`<div class="owner-panel"><div class="panel-title"><div><h3>حسابات المستفيدين</h3><p>عدّل بيانات الدخول أو المستوى، أو أنشئ كلمة مرور جديدة عند الحاجة.</p></div></div>${users.length?`<div class="table-scroll"><table class="data-table"><thead><tr><th>المستفيد</th><th>اسم المستخدم</th><th>المستوى</th><th>النقاط</th><th>الإجراءات</th></tr></thead><tbody>${users.map(u=>`<tr><td>${escapeHtml(u.name)}</td><td>${escapeHtml(u.username)}</td><td>${u.level}</td><td>${Number(u.points||0).toLocaleString("ar-SA")}</td><td><div class="table-actions"><button class="edit-button" onclick="openEditUser(${u.id})">تعديل الحساب</button><button class="delete-button" onclick="deleteUser(${u.id})">حذف</button></div></td></tr>`).join("")}</tbody></table></div>`:`<div class="empty-state">لم تتم إضافة مستفيدين بعد</div>`}</div>`}
return`<div class="stat-grid"><div class="stat-card"><strong>${authData.users.filter(u=>u.role==="student").length}</strong><span>مستفيد نشط</span></div><div class="stat-card"><strong>${authData.requests.filter(r=>r.status==="pending").length}</strong><span>طلب تسجيل جديد</span></div><div class="stat-card"><strong>24</strong><span>حلقة منشورة</span></div><div class="stat-card"><strong>${state.products.length}</strong><span>منتجات المتجر</span></div></div><div class="owner-panel"><h3>إدارة سريعة</h3><p>راجع طلبات التسجيل، أضف المستفيدين، ثم تابع نقاطهم وإنجازاتهم من لوحة واحدة.</p></div>`}

function openModal(content){document.querySelector("#modalContent").innerHTML=content;document.querySelector("#modalBackdrop").classList.add("open")}
function closeModal(){document.querySelector("#modalBackdrop").classList.remove("open")}
function showToast(text){const toast=document.querySelector("#toast");toast.textContent=text;toast.classList.add("show");setTimeout(()=>toast.classList.remove("show"),2600)}
async function saveChallengePoints(key){const input=document.querySelector(`#challengePoints-${key}`),maxPoints=Number(input?.value);try{await api(`owner/daily-challenge-settings/${key}`,{method:"PUT",body:JSON.stringify({maxPoints})});const setting=(state.challengeSettings||[]).find(item=>item.challenge_key===key);if(setting)setting.max_points=maxPoints;showToast("تم حفظ نقاط التحدي")}catch(error){showToast(error.message)}}
async function saveCompetitionPoints(id){const input=document.querySelector(`#competitionPoints-${id}`),points=Number(input?.value);try{await api(`owner/competition-settings/${id}`,{method:"PUT",body:JSON.stringify({points})});const setting=(state.competitionSettings||[]).find(item=>Number(item.competition_id)===id);if(setting)setting.points=points;const competition=competitions.find(item=>item.id===id);if(competition)competition.reward=points;showToast("تم حفظ نقاط المسابقة")}catch(error){showToast(error.message)}}
async function saveGameSetting(key){const input=document.querySelector(`#gameSetting-${key}`),value=Number(input?.value);try{await api(`owner/game-settings/${key}`,{method:"PUT",body:JSON.stringify({value})});const setting=(state.gameSettings||[]).find(item=>item.setting_key===key);if(setting)setting.setting_value=value;showToast("تم حفظ إعداد رصيد الألعاب")}catch(error){showToast(error.message)}}
async function saveManagerInstructions(){const title=document.querySelector("#managerInstructionsTitleInput")?.value.trim(),body=document.querySelector("#managerInstructionsBodyInput")?.value.trim();try{const data=await api("owner/manager-instructions",{method:"PUT",body:JSON.stringify({title,body})});state.managerInstructions=data;showToast("تم حفظ تعليمات المدير ونشرها 🎉")}catch(error){showToast(error.message)}}
async function loadOwnerChallengeRace(){const box=document.querySelector("#ownerRaceControl");if(!box)return;try{const data=await api("owner/challenge-race");box.className=`race-owner-control ${data.teaser?"teaser-active":"results-active"}`;box.innerHTML=`<div class="race-control-status"><span>${data.teaser?"👀":"🏁"}</span><div><small>الحالة الحالية</small><strong>${data.teaser?"ترقبوا إعلان الفائز":"النتائج ظاهرة للمستفيدين"}</strong></div></div><p>${data.teaser?"أسماء المشاركين ونقاطهم ومراكزهم محجوبة الآن.":`يظهر حاليًا ${(data.participants||[]).length.toLocaleString("ar-SA")} مشاركًا مرتبين حسب نقاطهم.`}</p><button class="race-toggle-button ${data.teaser?"show-results":"hide-results"}" onclick="setChallengeRaceTeaser(${data.teaser?"false":"true"})">${data.teaser?"🏁 إظهار النتائج":"👀 ترقبوا"}</button>`}catch(error){box.className="empty-state";box.textContent=error.message}}
async function setChallengeRaceTeaser(teaser){try{await api("owner/challenge-race",{method:"PUT",body:JSON.stringify({teaser})});await loadOwnerChallengeRace();showToast(teaser?"تم تفعيل وضع ترقبوا":"تم إظهار نتائج سباق التحدي")}catch(error){showToast(error.message)}}
function showStage(stage){const data={1:["بداية الرحلة","أكملت جميع المهام الأساسية وحصلت على شارة الانطلاق.","مكتملة"],2:["حديقة المعرفة","أنهيت 7 أنشطة في القراءة والحساب وجمعت 820 نقطة.","مكتملة"],3:["مرصد العلوم","أكمل نشاطين إضافيين لفتح تحدي الفضاء والحصول على 300 نقطة.","قيد التقدم"],4:["جزيرة الإبداع","تفتح بعد إكمال 80% من مرصد العلوم.","مغلقة"]};openModal(`<h2>${data[stage][0]}</h2><p>${data[stage][1]}</p><span class="status-badge" style="background:#e8f5f1">${data[stage][2]}</span><div class="modal-actions"><button class="outline-button" onclick="closeModal()">إغلاق</button></div>`)}
function openCompetition(id){if(state.completedCompetitions.includes(id))return showToast("أكملت هذه المسابقة بالفعل");const comp=competitions.find(c=>c.id===id);openModal(`<span class="eyebrow">السؤال 1 من 3</span><h2>${comp.title}</h2><p>ما الكوكب المعروف بالكوكب الأحمر؟</p><div class="quiz-options"><button class="quiz-option" onclick="finishCompetition(${id},${comp.reward},false)">الزهرة</button><button class="quiz-option" onclick="finishCompetition(${id},${comp.reward},true)">المريخ</button><button class="quiz-option" onclick="finishCompetition(${id},${comp.reward},false)">المشتري</button></div><button class="outline-button" onclick="closeModal()">إنهاء لاحقًا</button>`)}
async function finishCompetition(id,reward,correct){if(!correct)return showToast("إجابة قريبة، جرّب مرة أخرى");try{const result=await api("progress/award",{method:"POST",body:JSON.stringify({type:"competition",id})});state.points=result.points;currentUser.points=result.points;state.completedCompetitions.push(id);saveState();closeModal();renderCompetitions();showToast(`أحسنت! ربحت ${result.awarded} نقطة`)}catch(error){showToast(error.message)}}
function playEpisode(index){openModal(`<div class="card-visual ${episodes[index][4]}" style="border-radius:6px">${episodes[index][3]}</div><h2>${episodes[index][1]}</h2><p>سيظهر مشغل الحلقة التعليمية هنا، مع سؤال قصير بعد المشاهدة.</p><div class="modal-actions"><button class="outline-button" onclick="closeModal()">إغلاق</button><button class="primary-button" onclick="closeModal();showToast('تمت إضافة الحلقة إلى قائمة المتابعة')">أضف للمتابعة</button></div>`)}
function playGame(index){const game=games[index];openModal(`<h2>${game[0]}</h2><div class="daily-icon">${game[2]}</div><p>${game[1]}</p><div class="modal-actions"><button class="outline-button" onclick="closeModal()">لاحقًا</button><button class="primary-button" onclick="awardGame(${index})">ابدأ جولة سريعة</button></div>`)}
async function awardGame(index){try{const result=await api("progress/award",{method:"POST",body:JSON.stringify({type:"game",id:index})});state.points=result.points;currentUser.points=result.points;saveState();closeModal();showToast(`رائع! أضفنا ${result.awarded} نقطة إلى رصيدك`)}catch(error){showToast(error.message)}}
function buyProduct(id){const product=state.products.find(p=>p.id===id);if(!product||product.stock<1||state.points<product.price)return showToast("رصيدك لا يكفي لشراء هذا المنتج");openModal(`<h2>تأكيد الشراء</h2><div class="daily-icon">${product.icon}</div><p>هل تريد شراء <strong>${product.name}</strong> مقابل ${product.price.toLocaleString("ar-SA")} نقطة؟</p><div class="modal-actions"><button class="outline-button" onclick="closeModal()">تراجع</button><button class="primary-button" onclick="confirmPurchase(${id})">تأكيد الشراء</button></div>`)}
async function confirmPurchase(id){try{const result=await api("store/purchase",{method:"POST",body:JSON.stringify({productId:id})});state.points=result.points;currentUser.points=result.points;state.purchased.push({productId:id,date:new Date().toISOString()});saveState();closeModal();await renderStore();showToast("تم الشراء بنجاح، مبارك عليك المكافأة!")}catch(error){showToast(error.message)}}
function insertMajlisEmoji(id,value){const input=document.getElementById(id);if(!input)return;const start=input.selectionStart??input.value.length;input.value=input.value.slice(0,start)+value+input.value.slice(input.selectionEnd??start);input.focus();input.selectionStart=input.selectionEnd=start+value.length;input.dispatchEvent(new Event("input"))}
function toggleReplyBox(id){document.querySelector(`#reply-${id}`)?.classList.toggle("hidden");document.querySelector(`#reply-${id} textarea`)?.focus()}
async function majlisFileAsDataUrl(inputId){const file=document.getElementById(inputId)?.files?.[0];if(!file)return"";if(file.size>500*1024)throw new Error("حجم الصورة يجب ألا يتجاوز 500 كيلوبايت");return fileAsDataUrl(file)}
function previewMajlisImage(event,previewId){const file=event.target.files[0],box=document.getElementById(previewId);if(!file||!box)return;if(file.size>500*1024){event.target.value="";return showToast("حجم الصورة يجب ألا يتجاوز 500 كيلوبايت")}const reader=new FileReader();reader.onload=()=>{box.innerHTML=`<img src="${reader.result}" alt="معاينة الصورة"><button type="button" onclick="clearMajlisImage('${event.target.id}','${previewId}')">×</button>`;box.classList.remove("hidden")};reader.readAsDataURL(file)}
function clearMajlisImage(inputId,previewId){document.getElementById(inputId).value="";const box=document.getElementById(previewId);box.innerHTML="";box.classList.add("hidden")}
async function publishPost(){const input=document.querySelector("#postText"),content=input?.value.trim();try{const image=await majlisFileAsDataUrl("postImage");if(!content&&!image)return showToast("اكتب سالفتك أو أضف صورة");await api("majlis/posts",{method:"POST",body:JSON.stringify({content,type:"text",image})});await renderPosts();showToast("حيّ الله سالفتك في المجلس ☕")}catch(error){showToast(error.message)}}
async function publishSticker(content){try{await api("majlis/posts",{method:"POST",body:JSON.stringify({content,type:"sticker"})});await renderPosts();showToast("وصل الملصق للمقلط 🎭")}catch(error){showToast(error.message)}}
async function publishComment(postId,parentId,inputId){const input=document.getElementById(inputId),content=input?.value.trim();try{const image=await majlisFileAsDataUrl(`image-${inputId}`);if(!content&&!image)return showToast("اكتب ردك أو أضف صورة");await api(`majlis/posts/${postId}/comments`,{method:"POST",body:JSON.stringify({content,parentId,type:"text",image})});await renderPosts();showToast(parentId?"تم الرد على التعليق":"تمت إضافة تعليقك")}catch(error){showToast(error.message)}}
async function reactMajlis(type,id,reaction){try{await api(`majlis/${type}s/${id}/reaction`,{method:"POST",body:JSON.stringify({reaction})});await renderPosts()}catch(error){showToast(error.message)}}
function confirmDeleteMajlis(type,id){openModal(`<h2>حذف ${type==="post"?"السالفة":"التعليق"}</h2><p>هل أنت متأكد؟ سيُحذف المحتوى والردود التابعة له نهائيًا.</p><div class="modal-actions"><button class="outline-button" onclick="closeModal()">تراجع</button><button class="danger-button" onclick="deleteMajlis('${type}',${id})">نعم، حذف</button></div>`)}
async function deleteMajlis(type,id){try{await api(`majlis/${type}s/${id}`,{method:"DELETE"});closeModal();await renderPosts();showToast("تم الحذف بنجاح")}catch(error){showToast(error.message)}}
function openAchievementTaskForm(){if(currentUser?.role!=="owner")return;const today=new Date().toISOString().slice(0,10);openModal(`<h2>إضافة مهمة إنجاز يومية</h2><p>اختر فترة ظهور المهمة، وستتجدد يوميًا لجميع المستفيدين خلالها.</p><div class="form-grid"><div class="form-field full"><label>اسم المهمة</label><input id="achievementTaskTitle" maxlength="100" placeholder="مثال: أذكار الصباح"></div><div class="form-field"><label>القسم</label><select id="achievementTaskCategory">${Object.entries(achievementCategories).map(([key,item])=>`<option value="${key}">${item.icon} ${item.name}</option>`).join("")}</select></div><div class="form-field"><label>الدرجة اليومية</label><input id="achievementTaskPoints" type="number" min="1" max="10000" value="10"></div><div class="form-field"><label>تاريخ البداية</label><input id="achievementTaskStart" type="date" value="${today}"></div><div class="form-field"><label>تاريخ النهاية</label><input id="achievementTaskEnd" type="date" min="${today}"><small>اتركه فارغًا إذا كانت الفترة مفتوحة</small></div><div class="form-field full"><label>وصف مختصر (اختياري)</label><textarea id="achievementTaskDescription" maxlength="300" placeholder="تفاصيل تساعد المستفيد على إتمام المهمة"></textarea></div></div><div class="modal-actions"><button class="outline-button" onclick="closeModal()">إلغاء</button><button class="primary-button" onclick="saveAchievementTask()">إضافة المهمة</button></div>`);document.querySelector("#achievementTaskStart").addEventListener("change",event=>document.querySelector("#achievementTaskEnd").min=event.target.value)}
async function saveAchievementTask(){const payload={title:document.querySelector("#achievementTaskTitle").value.trim(),description:document.querySelector("#achievementTaskDescription").value.trim(),category:document.querySelector("#achievementTaskCategory").value,points:Number(document.querySelector("#achievementTaskPoints").value),startDate:document.querySelector("#achievementTaskStart").value,endDate:document.querySelector("#achievementTaskEnd").value};try{await api("owner/achievement-tasks",{method:"POST",body:JSON.stringify(payload)});closeModal();await renderOwner("achievements");showToast("تمت إضافة المهمة في الفترة المحددة")}catch(error){showToast(error.message)}}
async function toggleAchievementTask(id,active){try{await api(`owner/achievement-tasks/${id}`,{method:"PUT",body:JSON.stringify({active})});await renderOwner("achievements");showToast(active?"تم تفعيل المهمة":"تم إيقاف المهمة مع حفظ السجل السابق")}catch(error){showToast(error.message)}}
function openAddUser(){openModal(`<h2>إضافة مستفيد</h2><div class="form-grid"><div class="form-field full"><label>الاسم الكامل</label><input id="newUserName" placeholder="اسم المستفيد"></div><div class="form-field"><label>اسم المستخدم</label><input id="newUsername" placeholder="username"></div><div class="form-field"><label>كلمة المرور</label><input id="newUserPassword" type="password" placeholder="8 أحرف على الأقل"></div><div class="form-field"><label>المستوى</label><input id="newUserLevel" type="number" min="1" value="1"></div><div class="form-field"><label>النقاط الابتدائية</label><input id="newUserPoints" type="number" min="0" value="0"></div></div><div class="modal-actions"><button class="outline-button" onclick="closeModal()">إلغاء</button><button class="primary-button" onclick="addUser()">إنشاء الحساب</button></div>`)}
async function addUser(){const payload={name:document.querySelector("#newUserName").value.trim(),username:document.querySelector("#newUsername").value.trim(),password:document.querySelector("#newUserPassword").value,level:Number(document.querySelector("#newUserLevel").value)||1,points:Number(document.querySelector("#newUserPoints").value)||0};try{await api("owner/users",{method:"POST",body:JSON.stringify(payload)});closeModal();await renderOwner("students");showToast("تم إنشاء حساب المستفيد")}catch(error){showToast(error.message)}}
function openEditUser(id){const user=authData.users.find(item=>Number(item.id)===Number(id)&&item.role==="student");if(!user)return showToast("حساب المستفيد غير موجود");openModal(`<h2>تعديل حساب المستفيد</h2><p>يمكنك تعديل اسم المستخدم أو إنشاء كلمة مرور جديدة. اترك حقل كلمة المرور فارغًا للاحتفاظ بالكلمة الحالية.</p><div class="form-grid"><div class="form-field full"><label>الاسم الكامل</label><input id="editUserName" maxlength="80" value="${escapeHtml(user.name)}"></div><div class="form-field"><label>اسم المستخدم</label><input id="editUsername" maxlength="40" value="${escapeHtml(user.username)}" dir="ltr"></div><div class="form-field"><label>المستوى</label><input id="editUserLevel" type="number" min="1" max="20" value="${Number(user.level||1)}"></div><div class="form-field full"><label>كلمة مرور جديدة (اختياري)</label><input id="editUserPassword" type="password" minlength="8" maxlength="128" placeholder="اتركها فارغة لعدم تغيير كلمة المرور"><small>عند تغييرها سيتم تسجيل خروج المستفيد من أجهزته القديمة.</small></div></div><div class="modal-actions"><button class="outline-button" onclick="closeModal()">إلغاء</button><button class="primary-button" onclick="saveUserChanges(${user.id})">حفظ التعديلات</button></div>`)}
async function saveUserChanges(id){const payload={name:document.querySelector("#editUserName").value.trim(),username:document.querySelector("#editUsername").value.trim(),level:Number(document.querySelector("#editUserLevel").value)||1,password:document.querySelector("#editUserPassword").value};try{await api(`owner/users/${id}`,{method:"PUT",body:JSON.stringify(payload)});closeModal();await renderOwner("students");showToast("تم تحديث حساب المستفيد")}catch(error){showToast(error.message)}}
function approveRequest(id){const request=authData.requests.find(r=>r.id===id);if(!request)return;openModal(`<h2>قبول طلب ${request.name}</h2><p>حدد كلمة المرور الأولية وأرسلها إلى المستفيد.</p><div class="form-grid"><div class="form-field full"><label>اسم المستخدم</label><input id="approvedUsername" value="${request.username}"></div><div class="form-field"><label>كلمة المرور الأولية</label><input id="approvedPassword" value="Seif${String(id).slice(-4)}"></div><div class="form-field"><label>المستوى</label><input id="approvedLevel" type="number" min="1" value="1"></div></div><div class="modal-actions"><button class="outline-button" onclick="closeModal()">إلغاء</button><button class="primary-button" onclick="confirmApproval(${id})">اعتماد الحساب</button></div>`)}
async function confirmApproval(id){const username=document.querySelector("#approvedUsername").value.trim();const password=document.querySelector("#approvedPassword").value;try{await api(`owner/registration-requests/${id}/approve`,{method:"POST",body:JSON.stringify({username,password,level:Number(document.querySelector("#approvedLevel").value)||1})});closeModal();await renderOwner("requests");showToast(`تم اعتماد الحساب، كلمة المرور: ${password}`)}catch(error){showToast(error.message)}}
async function rejectRequest(id){try{await api(`owner/registration-requests/${id}/reject`,{method:"POST"});await renderOwner("requests");showToast("تم رفض الطلب")}catch(error){showToast(error.message)}}
async function deleteUser(id){try{await api(`owner/users/${id}`,{method:"DELETE"});await renderOwner("students");showToast("تم حذف حساب المستفيد")}catch(error){showToast(error.message)}}
function buyReward(id){const reward=(state.rewards||[]).find(item=>item.id===id);if(!reward||currentUser?.role!=="student")return;if(state.points<Number(reward.amount))return showToast("رصيدك لا يكفي لشراء هذه الجائزة");openModal(`<h2>تأكيد شراء الجائزة</h2><div class="purchase-reward-preview"><img src="${reward.image}" alt=""><div><strong>${escapeHtml(reward.name)}</strong><span>${formatRewardPoints(reward.amount)}</span></div></div><p>سيتم خصم النقاط من رصيدك وإرسال الطلب إلى مالك المنصة.</p><div class="modal-actions"><button class="outline-button" onclick="closeModal()">تراجع</button><button class="primary-button" onclick="confirmRewardPurchase(${id})">تأكيد الشراء</button></div>`)}
async function confirmRewardPurchase(id){try{const result=await api(`rewards/${id}/purchase`,{method:"POST"});state.points=result.points;currentUser.points=result.points;updatePoints();closeModal();await renderStore();showToast("ستصلك الجائزة قريبًا")}catch(error){showToast(error.message)}}
async function markOrderDelivered(id){if(currentUser?.role!=="owner")return;try{await api(`owner/reward-orders/${id}/delivered`,{method:"PUT"});await renderOwner("rewardOrders");showToast("تم تأكيد تسليم الجائزة")}catch(error){showToast(error.message)}}
function openRewardForm(id=null){if(currentUser?.role!=="owner")return showToast("هذه الصفحة مخصصة للمالك");const reward=id?(state.rewards||[]).find(item=>item.id===id):null;openModal(`<h2>${reward?"تعديل الجائزة":"إضافة جائزة جديدة"}</h2><div class="reward-form"><div class="reward-upload"><img id="rewardPreview" src="${reward?.image||""}" alt="معاينة الجائزة" class="${reward?.image?"":"hidden"}"><div id="rewardPlaceholder" class="reward-placeholder ${reward?.image?"hidden":""}">🎁<small>صورة الجائزة</small></div><label class="upload-button">اختيار صورة<input id="rewardImage" type="file" accept="image/png,image/jpeg,image/webp" hidden></label><small>PNG أو JPG أو WebP، بحد أقصى 650 كيلوبايت</small></div><div class="form-grid reward-fields"><div class="form-field full"><label>اسم الجائزة</label><input id="rewardName" maxlength="100" value="${escapeHtml(reward?.name||"")}" placeholder="مثال: قسيمة ألعاب"></div><div class="form-field"><label>تكلفة الجائزة بالنقاط</label><input id="rewardAmount" type="number" min="1" step="1" value="${reward?.amount||""}" placeholder="100"></div><div class="form-field"><label>تصنيف الجائزة</label><select id="rewardCategory"><option value="daily" ${reward?.category==="daily"?"selected":""}>جوائز يومية</option><option value="weekly" ${reward?.category==="weekly"?"selected":""}>جوائز أسبوعية</option><option value="grand" ${reward?.category==="grand"?"selected":""}>جوائز كبرى</option></select></div></div></div><div class="modal-actions"><button class="outline-button" onclick="closeModal()">إلغاء</button><button class="primary-button" onclick="saveReward(${id||"null"})">${reward?"حفظ التعديلات":"إضافة الجائزة"}</button></div>`);document.querySelector("#rewardImage").addEventListener("change",previewRewardImage)}
function previewRewardImage(event){const file=event.target.files[0];if(!file)return;if(file.size>650*1024){event.target.value="";return showToast("حجم الصورة أكبر من 650 كيلوبايت")}const reader=new FileReader();reader.onload=()=>{const preview=document.querySelector("#rewardPreview");preview.src=reader.result;preview.classList.remove("hidden");document.querySelector("#rewardPlaceholder").classList.add("hidden")};reader.readAsDataURL(file)}
function fileAsDataUrl(file){return new Promise((resolve,reject)=>{if(!file)return resolve("");if(file.size>650*1024)return reject(new Error("حجم الصورة أكبر من 650 كيلوبايت"));const reader=new FileReader();reader.onload=()=>resolve(reader.result);reader.onerror=()=>reject(new Error("تعذر قراءة الصورة"));reader.readAsDataURL(file)})}
async function saveReward(id){if(currentUser?.role!=="owner")return;const existing=id?(state.rewards||[]).find(item=>item.id===id):null;try{const uploaded=await fileAsDataUrl(document.querySelector("#rewardImage").files[0]);const payload={name:document.querySelector("#rewardName").value.trim(),amount:Number(document.querySelector("#rewardAmount").value),category:document.querySelector("#rewardCategory").value,image:uploaded||existing?.image||""};await api(id?`owner/rewards/${id}`:"owner/rewards",{method:id?"PUT":"POST",body:JSON.stringify(payload)});closeModal();await renderOwner("rewards");showToast(id?"تم تحديث الجائزة":"تمت إضافة الجائزة")}catch(error){showToast(error.message)}}
function removeReward(id){const reward=(state.rewards||[]).find(item=>item.id===id);if(!reward)return;openModal(`<h2>حذف الجائزة</h2><p>هل تريد حذف <strong>${escapeHtml(reward.name)}</strong>؟ لن تظهر بعد ذلك في المتجر.</p><div class="modal-actions"><button class="outline-button" onclick="closeModal()">تراجع</button><button class="danger-button" onclick="confirmRemoveReward(${id})">حذف الجائزة</button></div>`)}
async function confirmRemoveReward(id){if(currentUser?.role!=="owner")return;try{await api(`owner/rewards/${id}`,{method:"DELETE"});closeModal();await renderOwner("rewards");showToast("تم حذف الجائزة")}catch(error){showToast(error.message)}}
function openAddProduct(){openModal(`<h2>إضافة منتج جديد</h2><div class="form-grid"><div class="form-field full"><label>اسم المنتج</label><input id="productName" placeholder="مثال: قسيمة مقهى"></div><div class="form-field"><label>السعر بالنقاط</label><input id="productPrice" type="number" min="1" value="1000"></div><div class="form-field"><label>الكمية</label><input id="productStock" type="number" min="1" value="5"></div><div class="form-field"><label>رمز المنتج</label><input id="productIcon" value="🎁"></div><div class="form-field full"><label>الوصف</label><textarea id="productDesc" placeholder="وصف قصير للمنتج"></textarea></div></div><div class="modal-actions"><button class="outline-button" onclick="closeModal()">إلغاء</button><button class="primary-button" onclick="addProduct()">إضافة المنتج</button></div>`)}
async function addProduct(){const payload={name:document.querySelector("#productName").value.trim(),price:Number(document.querySelector("#productPrice").value),stock:Number(document.querySelector("#productStock").value),icon:document.querySelector("#productIcon").value||"🎁",description:document.querySelector("#productDesc").value||"مكافأة مميزة من دكان صيف"};try{await api("owner/products",{method:"POST",body:JSON.stringify(payload)});closeModal();await renderOwner("products");showToast("تمت إضافة المنتج إلى المتجر")}catch(error){showToast(error.message)}}
async function deleteProduct(id){try{await api(`owner/products/${id}`,{method:"DELETE"});await renderOwner("products");showToast("تم حذف المنتج")}catch(error){showToast(error.message)}}

{
const achievementAdminFilters={category:"",code:"",start:"",end:"",status:"",sort:"newest"};
const achievementStatusLabels={active:"نشطة",inactive:"غير نشطة",scheduled:"مجدولة",ended:"منتهية"};

async function renderAchievements(){const page=document.querySelector("#achievementsPage");page.innerHTML=`<div class="loading-state">جارٍ تحميل إنجازاتك...</div>`;try{const query=selectedAchievementDate?`?date=${selectedAchievementDate}`:"",data=await api(`achievements${query}`);selectedAchievementDate=data.date;const categories=data.categories||[];const grouped=categories.map(info=>{const tasks=data.tasks.filter(task=>String(task.category)===String(info.id));return`<section class="achievement-category"><div class="achievement-category-head"><span>${escapeHtml(info.icon||"🏆")}</span><div><h3>${escapeHtml(info.name)}</h3></div><b>${tasks.filter(task=>task.completed).length}/${tasks.length}</b></div><div class="achievement-list">${tasks.map(task=>`<button class="achievement-task ${task.completed?"completed":""}" ${task.completed||currentUser?.role!=="student"?"disabled":""} onclick="completeAchievementTask(${task.id})"><span class="achievement-check">${task.completed?"✓":""}</span><span><strong>${escapeHtml(task.title)}</strong><small>${escapeHtml(task.code||"")}${task.description?` · ${escapeHtml(task.description)}`:""}</small></span><b>+${Number(task.points).toLocaleString("ar-SA")} ★</b></button>`).join("")}</div></section>`}).join("");const earned=data.summary.badges.filter(b=>b.earned).length;page.innerHTML=`${pageBanner("إنجازات تتجدد كل يوم","ضع علامة عند إتمام المهمة، ويمكنك الرجوع للأيام السابقة واستدراك ما فاتك.")}<div class="achievement-date-bar"><button class="date-arrow" onclick="moveAchievementDate(-1)">اليوم السابق</button><div><small>إنجازات</small><strong>${achievementDateLabel(data.date,data.today)}</strong><input type="date" value="${data.date}" max="${data.today}" onchange="selectedAchievementDate=this.value;renderAchievements()"></div><button class="date-arrow" onclick="moveAchievementDate(1)" ${data.date>=data.today?"disabled":""}>اليوم التالي</button></div><div class="achievement-summary"><div><span>⭐</span><strong>${data.summary.points.toLocaleString("ar-SA")}</strong><small>نقاط الإنجازات</small></div><div><span>✅</span><strong>${data.summary.completedCount.toLocaleString("ar-SA")}</strong><small>مهمة مكتملة</small></div><div><span>🏅</span><strong>${earned}/${data.summary.badges.length}</strong><small>أوسمة مكتسبة</small></div></div><div class="achievement-grid">${grouped||`<div class="empty-state">لا توجد مهام متاحة في هذا اليوم.</div>`}</div>`}catch(error){page.innerHTML=`<div class="empty-state">${escapeHtml(error.message)}</div>`}}

function ownerAchievementsSection(){let tasks=[...(state.achievementTasks||[])];const categories=[...new Map(tasks.map(t=>[Number(t.category_id),{id:Number(t.category_id),name:t.category_name,icon:t.category_icon}])).values()];const f=achievementAdminFilters;if(f.category)tasks=tasks.filter(t=>String(t.category_id)===f.category);if(f.code)tasks=tasks.filter(t=>String(t.code||"").toLowerCase().includes(f.code.toLowerCase()));if(f.start)tasks=tasks.filter(t=>t.start_date>=f.start);if(f.end)tasks=tasks.filter(t=>(t.end_date||"9999-12-31")<=f.end);if(f.status)tasks=tasks.filter(t=>t.status===f.status);const sorters={newest:(a,b)=>b.id-a.id,category:(a,b)=>a.category_name.localeCompare(b.category_name,"ar"),code:(a,b)=>a.code.localeCompare(b.code),start:(a,b)=>a.start_date.localeCompare(b.start_date),end:(a,b)=>(a.end_date||"9999").localeCompare(b.end_date||"9999"),status:(a,b)=>a.status.localeCompare(b.status)};tasks.sort(sorters[f.sort]||sorters.newest);return`<div class="owner-panel achievement-admin"><div class="panel-title"><div><h3>مهام الإنجازات</h3><p>إدارة المهام اليومية والأقسام متاحة لمالك المنصة فقط.</p></div><button class="outline-button" onclick="openAchievementCategories()">إدارة الأقسام</button></div><div class="achievement-filters"><select onchange="achievementAdminFilters.category=this.value;renderOwner('achievements')"><option value="">كل الأقسام</option>${categories.map(c=>`<option value="${c.id}" ${f.category===String(c.id)?"selected":""}>${escapeHtml(c.icon||"")} ${escapeHtml(c.name)}</option>`).join("")}</select><input placeholder="تصفية بالرمز" value="${escapeHtml(f.code)}" oninput="achievementAdminFilters.code=this.value" onchange="renderOwner('achievements')"><input type="date" title="تاريخ البداية" value="${f.start}" onchange="achievementAdminFilters.start=this.value;renderOwner('achievements')"><input type="date" title="تاريخ النهاية" value="${f.end}" onchange="achievementAdminFilters.end=this.value;renderOwner('achievements')"><select onchange="achievementAdminFilters.status=this.value;renderOwner('achievements')"><option value="">كل الحالات</option>${Object.entries(achievementStatusLabels).map(([k,v])=>`<option value="${k}" ${f.status===k?"selected":""}>${v}</option>`).join("")}</select><select onchange="achievementAdminFilters.sort=this.value;renderOwner('achievements')"><option value="newest">الأحدث</option><option value="category" ${f.sort==="category"?"selected":""}>القسم</option><option value="code" ${f.sort==="code"?"selected":""}>الرمز</option><option value="start" ${f.sort==="start"?"selected":""}>تاريخ البداية</option><option value="end" ${f.sort==="end"?"selected":""}>تاريخ النهاية</option><option value="status" ${f.sort==="status"?"selected":""}>الحالة</option></select></div>${tasks.length?`<div class="table-scroll"><table class="data-table"><thead><tr><th>المهمة</th><th>القسم</th><th>الرمز</th><th>الدرجة</th><th>الفترة</th><th>الحالة</th><th>الإجراءات</th></tr></thead><tbody>${tasks.map(t=>`<tr><td><strong>${escapeHtml(t.title)}</strong><small class="table-subtext">${escapeHtml(t.description||"")}</small></td><td>${escapeHtml(t.category_icon||"")} ${escapeHtml(t.category_name)}</td><td><code>${escapeHtml(t.code)}</code></td><td>${Number(t.points).toLocaleString("ar-SA")}</td><td>${t.start_date}<br>${t.end_date||"مفتوحة"}</td><td><span class="achievement-status ${t.status}">${achievementStatusLabels[t.status]}</span></td><td><div class="row-actions"><button onclick="openAchievementTaskForm(${t.id})">تعديل</button><button onclick="toggleAchievementTask(${t.id},${t.active?"false":"true"})">${t.active?"إيقاف":"تفعيل"}</button><button class="danger-link" onclick="confirmDeleteAchievementTask(${t.id})">حذف</button></div></td></tr>`).join("")}</tbody></table></div>`:`<div class="empty-state">لا توجد مهام مطابقة.</div>`}</div>`}

async function achievementCategoryOptions(selected){const data=await api("owner/achievement-categories");return{categories:data.categories,html:data.categories.map(c=>`<option value="${c.id}" ${Number(selected)===Number(c.id)?"selected":""}>${escapeHtml(c.icon)} ${escapeHtml(c.name)}</option>`).join("")}}
async function openAchievementTaskForm(id=null){if(currentUser?.role!=="owner")return;try{const task=id?(state.achievementTasks||[]).find(t=>Number(t.id)===Number(id)):null,cats=await achievementCategoryOptions(task?.category_id),today=new Intl.DateTimeFormat("en-CA",{timeZone:"Asia/Riyadh"}).format(new Date());openModal(`<h2>${task?"تعديل مهمة الإنجاز":"إضافة مهمة إنجاز"}</h2><div class="form-grid"><div class="form-field"><label>القسم</label><select id="achievementTaskCategory">${cats.html}</select></div><div class="form-field"><label>الرمز</label><input id="achievementTaskCode" maxlength="40" dir="ltr" value="${escapeHtml(task?.code||"")}" placeholder="DAILY-01"></div><div class="form-field full"><label>اسم المهمة</label><input id="achievementTaskTitle" maxlength="100" value="${escapeHtml(task?.title||"")}"></div><div class="form-field"><label>الدرجة اليومية</label><input id="achievementTaskPoints" type="number" min="1" max="10000" value="${task?.points||10}"></div><div class="form-field"><label>تاريخ البداية</label><input id="achievementTaskStart" type="date" value="${task?.start_date||today}"></div><div class="form-field"><label>تاريخ النهاية</label><input id="achievementTaskEnd" type="date" value="${task?.end_date||""}"></div><div class="form-field full"><label>الوصف المختصر</label><textarea id="achievementTaskDescription" maxlength="300">${escapeHtml(task?.description||"")}</textarea></div></div><div class="modal-actions"><button class="outline-button" onclick="closeModal()">إلغاء</button><button class="primary-button" onclick="saveAchievementTask(${id||"null"})">حفظ المهمة</button></div>`)}catch(error){showToast(error.message)}}
async function saveAchievementTask(id=null){const payload={categoryId:Number(document.querySelector("#achievementTaskCategory").value),code:document.querySelector("#achievementTaskCode").value.trim(),title:document.querySelector("#achievementTaskTitle").value.trim(),points:Number(document.querySelector("#achievementTaskPoints").value),startDate:document.querySelector("#achievementTaskStart").value,endDate:document.querySelector("#achievementTaskEnd").value,description:document.querySelector("#achievementTaskDescription").value.trim()};try{await api(id?`owner/achievement-tasks/${id}`:"owner/achievement-tasks",{method:id?"PUT":"POST",body:JSON.stringify(payload)});closeModal();await renderOwner("achievements");showToast(id?"تم تحديث المهمة":"تمت إضافة المهمة")}catch(error){showToast(error.message)}}
function confirmDeleteAchievementTask(id){const task=(state.achievementTasks||[]).find(t=>Number(t.id)===Number(id));openModal(`<h2>حذف المهمة</h2><p>هل تريد حذف <strong>${escapeHtml(task?.title||"")}</strong>؟ سيُحفظ سجل النقاط السابق.</p><div class="modal-actions"><button class="outline-button" onclick="closeModal()">تراجع</button><button class="danger-button" onclick="deleteAchievementTask(${id})">حذف</button></div>`)}
async function deleteAchievementTask(id){try{await api(`owner/achievement-tasks/${id}`,{method:"DELETE"});closeModal();await renderOwner("achievements");showToast("تم حذف المهمة")}catch(error){showToast(error.message)}}
async function openAchievementCategories(){try{const data=await api("owner/achievement-categories");openModal(`<h2>إدارة أقسام الإنجازات</h2><div class="category-create"><input id="newCategoryIcon" maxlength="8" value="🏆" aria-label="الرمز"><input id="newCategoryName" maxlength="60" placeholder="اسم القسم الجديد"><button class="primary-button" onclick="saveAchievementCategory()">إضافة قسم</button></div><div class="category-list">${data.categories.map(c=>`<div><input id="categoryIcon-${c.id}" maxlength="8" value="${escapeHtml(c.icon)}"><input id="categoryName-${c.id}" maxlength="60" value="${escapeHtml(c.name)}"><small>${Number(c.task_count)} مهمة</small><button onclick="saveAchievementCategory(${c.id})">حفظ</button><button class="danger-link" onclick="deleteAchievementCategory(${c.id})" ${Number(c.task_count)>0?"disabled title=\"القسم مرتبط بمهام\"":""}>حذف</button></div>`).join("")}</div><div class="modal-actions"><button class="outline-button" onclick="closeModal()">إغلاق</button></div>`)}catch(error){showToast(error.message)}}
async function saveAchievementCategory(id=null){const name=document.querySelector(id?`#categoryName-${id}`:"#newCategoryName").value.trim(),icon=document.querySelector(id?`#categoryIcon-${id}`:"#newCategoryIcon").value.trim();try{await api(id?`owner/achievement-categories/${id}`:"owner/achievement-categories",{method:id?"PUT":"POST",body:JSON.stringify({name,icon})});await openAchievementCategories();showToast(id?"تم تعديل القسم":"تمت إضافة القسم")}catch(error){showToast(error.message)}}
async function deleteAchievementCategory(id){try{await api(`owner/achievement-categories/${id}`,{method:"DELETE"});await openAchievementCategories();showToast("تم حذف القسم")}catch(error){showToast(error.message)}}
Object.assign(window,{achievementAdminFilters,renderAchievements,ownerAchievementsSection,openAchievementTaskForm,saveAchievementTask,confirmDeleteAchievementTask,deleteAchievementTask,openAchievementCategories,saveAchievementCategory,deleteAchievementCategory});
}

document.addEventListener("click",event=>{const trigger=event.target.closest("[data-page]");if(trigger)navigate(trigger.dataset.page);if(event.target.id==="modalBackdrop")closeModal()});
document.querySelectorAll("[data-auth-view]").forEach(tab=>tab.addEventListener("click",()=>switchAuthView(tab.dataset.authView)));
document.querySelector("#loginForm").addEventListener("submit",async event=>{event.preventDefault();const message=document.querySelector("#loginMessage");message.textContent="جارٍ تسجيل الدخول...";try{await login(document.querySelector("#loginUsername").value,document.querySelector("#loginPassword").value);message.textContent=""}catch(error){message.textContent=error.message;message.classList.remove("success")}});
document.querySelector("#requestForm").addEventListener("submit",event=>{event.preventDefault();submitRegistration()});
document.querySelector("#logoutButton").addEventListener("click",logout);
document.querySelector("#refreshPageButton").addEventListener("click",()=>{const activePage=document.querySelector(".page.active"),page=activePage?.id.replace(/Page$/,"")||"home";if(page==="owner"){const action=document.querySelector(".owner-tab.active")?.getAttribute("onclick")||"",section=action.match(/renderOwner\('([^']+)'\)/)?.[1]||"overview";renderOwner(section)}else renderPage(page);showToast("تم تحديث الصفحة الحالية")});
document.addEventListener("keydown",e=>{if(e.key==="Escape")closeModal()});
(async function restoreSession(){try{const data=await api("auth/me");currentUser=data.user;showApp()}catch{document.querySelector("#authScreen").classList.remove("hidden")}})();
